// Webhook-Input lesen
const webhookInput = $('Webhook: Pre-Check').first().json;
const input = webhookInput.body || webhookInput;
const titel = (input['Titel'] || '').toString().trim();
const kurzbeschreibung = (input['Kurzbeschreibung'] || '').toString().trim();

return { json: {
  titel,
  kurzbeschreibung,
  // Original wird im Response-Parser zurückgereicht (vor LLM-Modifikation gesichert)
  _originalTitel: titel,
  _originalKurzbeschreibung: kurzbeschreibung
}};

// LLM-Output parsen + Schema validieren + Fail-Open-Defaults
const orig = $('Eingabe vorbereiten').first().json;
const rawText = ($input.item.json.text || '').toString();

const originalTitel = orig._originalTitel || '';
const originalKurzbeschreibung = orig._originalKurzbeschreibung || '';

function failOpen(reason) {
  return { json: {
    status: 'ok',
    original: { titel: originalTitel, kurzbeschreibung: originalKurzbeschreibung },
    corrected: { titel: originalTitel, kurzbeschreibung: originalKurzbeschreibung },
    issues: [],
    _debug: { failOpenReason: reason }
  }};
}

// JSON aus Text extrahieren (LLM kann Code-Blöcke trotz Anweisung liefern)
const match = rawText.match(/\{[\s\S]*\}/);
if (!match) return failOpen('no-json-found');

let parsed;
try { parsed = JSON.parse(match[0]); } catch (e) { return failOpen('parse-error'); }

const validStatus = ['ok', 'corrected', 'rejected'];
let status = validStatus.includes(parsed.status) ? parsed.status : 'ok';

const correctedTitel = (parsed.corrected && typeof parsed.corrected.titel === 'string')
  ? parsed.corrected.titel : originalTitel;
const correctedKurz  = (parsed.corrected && typeof parsed.corrected.kurzbeschreibung === 'string')
  ? parsed.corrected.kurzbeschreibung : originalKurzbeschreibung;

let issues = Array.isArray(parsed.issues) ? parsed.issues.filter(i =>
  i && typeof i === 'object' &&
  ['titel', 'kurzbeschreibung'].includes(i.feld) &&
  ['grammatik', 'jugendfrei'].includes(i.typ) &&
  typeof i.grund === 'string'
) : [];

// Bei rejected: corrected immer auf Original, damit Frontend keine LLM-entschärfte Variante anzeigt
let finalCorrected = status === 'rejected'
  ? { titel: originalTitel, kurzbeschreibung: originalKurzbeschreibung }
  : { titel: correctedTitel, kurzbeschreibung: correctedKurz };

// Bei ok: corrected = Original (schon vom LLM so gemeint, aber sicherheitshalber)
if (status === 'ok') {
  finalCorrected = { titel: originalTitel, kurzbeschreibung: originalKurzbeschreibung };
}

// Downgrade corrected → ok, wenn keine echte Textänderung vorliegt UND keine jugendfrei-Issues
// (Fallback gegen LLM-Halluzinationen wo issues angegeben werden, aber corrected === original)
if (status === 'corrected' &&
    finalCorrected.titel === originalTitel &&
    finalCorrected.kurzbeschreibung === originalKurzbeschreibung) {
  const hasJugendfrei = issues.some(i => i.typ === 'jugendfrei');
  if (!hasJugendfrei) {
    status = 'ok';
    issues = [];
  }
}

return { json: {
  status,
  original: { titel: originalTitel, kurzbeschreibung: originalKurzbeschreibung },
  corrected: finalCorrected,
  issues
}};
